SELECT de.* FROM daily_expenses de
AND year = #{condition.year}
AND month = #{condition.month}
AND day = #{condition.day}
AND single_expense LIKE CONCAT('%', #{condition.singleExpense}, '%')
AND expense_reason LIKE CONCAT('%', #{condition.expenseReason}, '%')
AND expense_content LIKE CONCAT('%', #{condition.expenseContent}, '%')
AND daily_total LIKE CONCAT('%', #{condition.dailyTotal}, '%')
AND ( year LIKE CONCAT('%', #{condition.key}, '%') OR month LIKE CONCAT('%', #{condition.key}, '%') OR day LIKE CONCAT('%', #{condition.key}, '%') OR single_expense LIKE CONCAT('%', #{condition.key}, '%') OR expense_reason LIKE CONCAT('%', #{condition.key}, '%') OR expense_content LIKE CONCAT('%', #{condition.key}, '%') OR daily_total LIKE CONCAT('%', #{condition.key}, '%') )
ORDER BY year DESC, month DESC, day DESC

SELECT de.*, u.name create_by_name, u2.name update_by_name FROM daily_expenses de left join users u on u.id=de.create_by left join users u2 on u2.id=de.update_by
AND year = #{condition.year}
AND month = #{condition.month}
AND day = #{condition.day}
AND single_expense LIKE CONCAT('%', #{condition.singleExpense}, '%')
AND expense_reason LIKE CONCAT('%', #{condition.expenseReason}, '%')
AND expense_content LIKE CONCAT('%', #{condition.expenseContent}, '%')
AND daily_total LIKE CONCAT('%', #{condition.dailyTotal}, '%')
AND ( year LIKE CONCAT('%', #{condition.key}, '%') OR month LIKE CONCAT('%', #{condition.key}, '%') OR day LIKE CONCAT('%', #{condition.key}, '%') OR single_expense LIKE CONCAT('%', #{condition.key}, '%') OR expense_reason LIKE CONCAT('%', #{condition.key}, '%') OR expense_content LIKE CONCAT('%', #{condition.key}, '%') OR daily_total LIKE CONCAT('%', #{condition.key}, '%') )
ORDER BY year DESC, month DESC, day DESC, create_time desc, update_time desc
